INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES(364, 59, '_mission_text', 'field_65d8c1e2f3a55');
INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES(365, 59, 'vision_text', 'Our vision is to create a world where advertising becomes an experience rather than just something people watch. We believe in meaningful, immersive interactions that connect brands with audiences in real, memorable ways.');
